// =========================================================================
// Title: Winds of Io (High Quality - Optimized)
// Author: Procedural Volumetrics for Surfaces Explorer
// License: MIT
// =========================================================================

const mat3 m3 = mat3( 0.33338, 0.56034, -0.71817, 
                     -0.87887, 0.32651, -0.15323, 
                      0.15162, 0.69596,  0.61339 ) * 1.93;

float hash(float n) { return fract(sin(n) * 43758.5453123); }

float noise(in vec3 x) {
    vec3 i = floor(x);
    vec3 f = fract(x);
    f = f * f * (3.0 - 2.0 * f);
    float n = i.x + i.y * 157.0 + 113.0 * i.z;

    return mix(
        mix(mix(hash(n +   0.0), hash(n +   1.0), f.x),
            mix(hash(n + 157.0), hash(n + 158.0), f.x), f.y),
        mix(mix(hash(n + 113.0), hash(n + 114.0), f.x),
            mix(hash(n + 270.0), hash(n + 271.0), f.x), f.y), f.z);
}

// TORNATO AL MASSIMO DETTAGLIO: 4 Ottave di FBM per avere i "ciuffi"
float fbm(in vec3 q) {
    float f = 0.0;
    float weight = 0.5;
    for (int i = 0; i < 4; i++) { 
        f += weight * noise(q);
        q = m3 * q;
        weight *= 0.5;
    }
    return f;
}

// Scultura della forma intatta
float map(in vec3 p) {
    float heightProfile = 1.0 - abs(p.y - 0.5); 
    if (heightProfile <= 0.0) return 0.0; 

    vec3 q = p;
    q.z -= iTime * 0.2; 

    vec3 warp = vec3(fbm(q * 0.5), fbm(q * 0.5 + 13.3), 0.0);
    float n = fbm(q * 1.5 + warp);

    float density = (n - 0.45) * heightProfile * 2.0;
    return max(0.0, density);
}

// RAYMARCHING INTELLIGENTE
vec4 renderClouds(in vec3 ro, in vec3 rd) {
    vec4 sum = vec4(0.0);
    float t = 0.0;

    vec3 lightDir = normalize(vec3(0.8, 0.4, -0.3)); 
    vec3 sunCol = vec3(1.0, 0.55, 0.1);               
    vec3 ambCol = vec3(0.4, 0.15, 0.05);               

    // 35 passi: il perfetto equilibrio tra fluidità e profondità volumetrica
    for(int i = 0; i < 35; i++) { 
        if(sum.a > 0.98) break;

        vec3 pos = ro + t * rd;
        float den = map(pos);

        if(den > 0.01) {
            // IL TRUCCO DELLE OMBRE: Misuriamo la densità poco più in là verso il sole
            // Se la densità diminuisce (cioè usciamo dalla nuvola), significa che quella parte è esposta alla luce!
            float denVersoIlSole = map(pos + lightDir * 0.3);

            // Calcoliamo la differenza per generare ombre perfette senza cicli extra
            float dif = clamp((den - denVersoIlSole) * 4.0, 0.0, 1.0);

            // Effetto Powder per schiarire i bordi
            float powder = 1.0 - exp(-den * 3.0);

            vec3 lighting = ambCol + sunCol * (dif + 0.1) * powder * 1.5;

            vec4 col = vec4(lighting, den);
            col.a *= 0.5; // Morbidezza originale
            col.rgb *= col.a; 

            sum += col * (1.0 - sum.a);
        }

        t += max(0.05, 0.12 * (1.0 - den));
    }

    return clamp(sum, 0.0, 1.0);
}

void mainImage( out vec4 fragColor, in vec2 fragCoord ) {
    // FIX: Usa fragCoord (che contiene le trasformazioni del tuo motore) invece di gl_FragCoord
    vec2 p = (fragCoord - 0.5 * iResolution.xy) / iResolution.y;

    vec3 ro = vec3(0.0, 0.2, iTime * 0.5); 
    vec3 rd = normalize(vec3(p.x, p.y + 0.2, 1.0)); 

    vec3 skyColor = mix(vec3(0.3, 0.1, 0.05), vec3(0.9, 0.4, 0.1), clamp(rd.y + 0.1, 0.0, 1.0));

    vec4 clouds = renderClouds(ro, rd);
    vec3 finalColor = mix(skyColor, clouds.rgb, clouds.a);

    float distanceFog = 1.0 - exp(-0.02 * clouds.a);
    finalColor = mix(finalColor, skyColor, distanceFog);

    finalColor = smoothstep(0.0, 1.0, finalColor);

    // FIX: Usa fragCoord anche per la vignettatura
    vec2 q = fragCoord / iResolution.xy;
    float vig = max(0.0, 16.0 * q.x * q.y * (1.0 - q.x) * (1.0 - q.y));
    finalColor *= pow(vig, 0.15) * 0.7 + 0.3;

    fragColor = vec4(finalColor, 1.0);
}

